### 1. Zod Error Transformer
```typescript
// packages/shared/src/api/zod-transform.ts

import { ZodError, ZodIssue, ZodIssueCode } from "zod";

export interface TransformedValidationError {
  param: string;
  message: string;
  code: string;
  received?: unknown;
  expected?: unknown;
}

/**
 * Transform a Zod error into user-friendly validation errors.
 */
export function transformZodError(
  error: ZodError
): TransformedValidationError[] {
  return error.issues.map(transformIssue);
}

/**
 * Get a single error message for display.
 */
export function getZodErrorMessage(error: ZodError): string {
  const firstIssue = error.issues[0];
  if (!firstIssue) return "Validation failed";

  const param = formatPath(firstIssue.path);
  return transformIssue(firstIssue).message;
}

function transformIssue(issue: ZodIssue): TransformedValidationError {
  const param = formatPath(issue.path);

  switch (issue.code) {
    case ZodIssueCode.invalid_type:
      if (issue.received === "undefined") {
        return {
          param,
          message: `${param} is required`,
          code: "required",
        };
      }
      return {
        param,
        message: `${param} must be a ${issue.expected}`,
        code: "invalid_type",
        expected: issue.expected,
        received: issue.received,
      };

    case ZodIssueCode.too_small:
      if (issue.type === "string" && issue.minimum === 1) {
        return {
          param,
          message: `${param} cannot be empty`,
          code: "too_short",
        };
      }
      return {
        param,
        message: `${param} must be at least ${issue.minimum}`,
        code: "too_small",
        expected: issue.minimum,
      };

    case ZodIssueCode.too_big:
      return {
        param,
        message: `${param} must be at most ${issue.maximum}`,
        code: "too_big",
        expected: issue.maximum,
      };

    case ZodIssueCode.invalid_enum_value:
      const options = issue.options.join(", ");
      return {
        param,
        message: `${param} must be one of: ${options}`,
        code: "invalid_enum",
        expected: issue.options,
        received: issue.received,
      };

    case ZodIssueCode.invalid_string:
      if (issue.validation === "email") {
        return { param, message: `${param} must be a valid email`, code: "invalid_email" };
      }
      if (issue.validation === "url") {
        return { param, message: `${param} must be a valid URL`, code: "invalid_url" };
      }
      if (issue.validation === "uuid") {
        return { param, message: `${param} must be a valid UUID`, code: "invalid_uuid" };
      }
      return { param, message: `${param} has invalid format`, code: "invalid_string" };

    case ZodIssueCode.custom:
      return {
        param,
        message: issue.message || `${param} is invalid`,
        code: "custom",
      };

    default:
      return {
        param,
        message: issue.message || `${param} is invalid`,
        code: issue.code,
      };
  }
}

/**
 * Format path array as dot notation string.
 * ["foo", "bar", 0, "baz"] → "foo.bar[0].baz"
 */
function formatPath(path: (string | number)[]): string {
  return path.reduce((acc, segment, i) => {
    if (typeof segment === "number") {
      return `${acc}[${segment}]`;
    }
    return i === 0 ? segment : `${acc}.${segment}`;
  }, "") as string;
}
```

