 {"id":"flywheel_gateway-r9y","title":"DCG: Improve Statistics Service (Full Database Queries)","description":"## Problem Statement

The current DCG statistics service uses in-memory data and sample data. It needs to be updated to query the actual database tables with proper aggregations for real-time insights.

## Background

Current `dcg.service.ts` returns mock/sample data:

```typescript
export function getStats(): DCGStats {
  return {
    totalBlocks: 42,        // Hardcoded!
    blocksToday: 5,         // Hardcoded!
    topPatterns: [...],     // Sample data
    recentBlocks: [...],    // Sample data
  };
}
```

Users need real statistics including:
- Total blocks over time with trending
- Blocks by severity distribution
- Top triggered rules (which rules catch the most)
- Blocks by pack (which areas are most dangerous)
- Blocks by agent (which agents trigger most blocks)
- False positive rate
- Allowlist effectiveness
- Time-series data for charts

## Implementation Plan

### 1. Statistics Service

```typescript
// apps/gateway/src/services/dcg-stats.service.ts

import { db } from "../db";
import { dcgBlocks, dcgAllowlist, dcgPendingExceptions } from "../db/schema";
import { sql, count, desc, eq, and, gte, lt } from "drizzle-orm";
import { logger } from "./logger";

interface DCGOverviewStats {
  totalBlocks: number;
  blocksLast24h: number;
  blocksLast7d: number;
  blocksLast30d: number;
  falsePositiveCount: number;
  falsePositiveRate: number;
  allowlistSize: number;
  pendingExceptionsCount: number;
  trendVsYesterday: number;  // Percentage change
  trendVsLastWeek: number;
}

interface SeverityDistribution {
  critical: number;
  high: number;
  medium: number;
  low: number;
}

interface TopRule {
  ruleId: string;
  pack: string;
  pattern: string;
  blockCount: number;
  lastTriggered: Date;
  falsePositiveCount: number;
}

interface PackStats {
  pack: string;
  blockCount: number;
  percentage: number;
  rules: number;
  topRules: string[];
}

interface AgentStats {
  agentId: string;
  blockCount: number;
  percentage: number;
  topRules: string[];
  lastBlock: Date;
}

interface TimeSeriesPoint {
  timestamp: Date;
  count: number;
  severity?: string;
}

interface DCGStats {
  overview: DCGOverviewStats;
  severityDistribution: SeverityDistribution;
  topRules: TopRule[];
  packStats: PackStats[];
  agentStats: AgentStats[];
  timeSeries: {
    hourly: TimeSeriesPoint[];
    daily: TimeSeriesPoint[];
  };
  recentBlocks: DCGBlockEvent[];
}

export async function getStats(): Promise<DCGStats> {
  const correlationId = getCorrelationId();
  const startTime = Date.now();

  const [
    overview,
    severityDistribution,
    topRules,
    packStats,
    agentStats,
    hourlyTimeSeries,
    dailyTimeSeries,
    recentBlocks,
  ] = await Promise.all([
    getOverviewStats(),
    getSeverityDistribution(),
    getTopRules(10),
    getPackStats(),
    getAgentStats(10),
    getHourlyTimeSeries(24),
    getDailyTimeSeries(30),
    getRecentBlocks(20),
  ]);

  const stats: DCGStats = {
    overview,
    severityDistribution,
    topRules,
    packStats,
    agentStats,
    timeSeries: {
      hourly: hourlyTimeSeries,
      daily: dailyTimeSeries,
    },
    recentBlocks,
  };

  logger.info({
    correlationId,
    duration_ms: Date.now() - startTime,
    totalBlocks: overview.totalBlocks,
    blocksLast24h: overview.blocksLast24h,
  }, "Generated DCG statistics");

  return stats;
}

async function getOverviewStats(): Promise<DCGOverviewStats> {
  const now = Date.now();
  const yesterday = now - 24 * 60 * 60 * 1000;
  const lastWeek = now - 7 * 24 * 60 * 60 * 1000;
  const lastMonth = now - 30 * 24 * 60 * 60 * 1000;
  const dayBeforeYesterday = now - 48 * 60 * 60 * 1000;
  const twoWeeksAgo = now - 14 * 24 * 60 * 60 * 1000;

  const [
    totalResult,
    last24hResult,
    last7dResult,
    last30dResult,
    falsePositiveResult,
    allowlistResult,
    pendingResult,
    yesterdayResult,
    lastWeekResult,
  ] = await Promise.all([
    db.select({ count: count() }).from(dcgBlocks),
    db.select({ count: count() }).from(dcgBlocks)
      .where(gte(dcgBlocks.createdAt, new Date(yesterday))),
    db.select({ count: count() }).from(dcgBlocks)
      .where(gte(dcgBlocks.createdAt, new Date(lastWeek))),
    db.select({ count: count() }).from(dcgBlocks)
      .where(gte(dcgBlocks.createdAt, new Date(lastMonth))),
    db.select({ count: count() }).from(dcgBlocks)
      .where(eq(dcgBlocks.falsePositive, true)),
    db.select({ count: count() }).from(dcgAllowlist),
    db.select({ count: count() }).from(dcgPendingExceptions)
      .where(eq(dcgPendingExceptions.status, "pending")),
    // For trend calculation
    db.select({ count: count() }).from(dcgBlocks)
      .where(and(
        gte(dcgBlocks.createdAt, new Date(dayBeforeYesterday)),
        lt(dcgBlocks.createdAt, new Date(yesterday))
      )),
    db.select({ count: count() }).from(dcgBlocks)
      .where(and(
        gte(dcgBlocks.createdAt, new Date(twoWeeksAgo)),
        lt(dcgBlocks.createdAt, new Date(lastWeek))
      )),
  ]);

  const total = totalResult[0]?.count || 0;
  const last24h = last24hResult[0]?.count || 0;
  const yesterdayCount = yesterdayResult[0]?.count || 1; // Avoid division by zero
  const lastWeekCount = lastWeekResult[0]?.count || 1;

  return {
    totalBlocks: total,
    blocksLast24h: last24h,
    blocksLast7d: last7dResult[0]?.count || 0,
    blocksLast30d: last30dResult[0]?.count || 0,
    falsePositiveCount: falsePositiveResult[0]?.count || 0,
    falsePositiveRate: total > 0 ? (falsePositiveResult[0]?.count || 0) / total : 0,
    allowlistSize: allowlistResult[0]?.count || 0,
    pendingExceptionsCount: pendingResult[0]?.count || 0,
    trendVsYesterday: ((last24h - yesterdayCount) / yesterdayCount) * 100,
    trendVsLastWeek: (((last7dResult[0]?.count || 0) - lastWeekCount) / lastWeekCount) * 100,
  };
}

async function getSeverityDistribution(): Promise<SeverityDistribution> {
  const result = await db
    .select({
      severity: dcgBlocks.severity,
      count: count(),
    })
    .from(dcgBlocks)
    .groupBy(dcgBlocks.severity);

  const distribution: SeverityDistribution = {
    critical: 0,
    high: 0,
    medium: 0,
    low: 0,
  };

  for (const row of result) {
    if (row.severity in distribution) {
      distribution[row.severity as keyof SeverityDistribution] = row.count;
    }
  }

  return distribution;
}

async function getTopRules(limit: number): Promise<TopRule[]> {
  const result = await db
    .select({
      ruleId: dcgBlocks.ruleId,
      pack: dcgBlocks.pack,
      pattern: dcgBlocks.pattern,
      blockCount: count(),
      lastTriggered: sql<Date>`MAX(${dcgBlocks.createdAt})`,
      falsePositiveCount: sql<number>`SUM(CASE WHEN ${dcgBlocks.falsePositive} THEN 1 ELSE 0 END)`,
    })
    .from(dcgBlocks)
    .groupBy(dcgBlocks.ruleId, dcgBlocks.pack, dcgBlocks.pattern)
    .orderBy(desc(count()))
    .limit(limit);

  return result.map(row => ({
    ruleId: row.ruleId,
    pack: row.pack,
    pattern: row.pattern,
    blockCount: row.blockCount,
    lastTriggered: row.lastTriggered,
    falsePositiveCount: row.falsePositiveCount || 0,
  }));
}

async function getPackStats(): Promise<PackStats[]> {
  const totalBlocks = await db.select({ count: count() }).from(dcgBlocks);
  const total = totalBlocks[0]?.count || 1;

  const result = await db
    .select({
      pack: dcgBlocks.pack,
      blockCount: count(),
      rules: sql<number>`COUNT(DISTINCT ${dcgBlocks.ruleId})`,
    })
    .from(dcgBlocks)
    .groupBy(dcgBlocks.pack)
    .orderBy(desc(count()));

  // Get top rules per pack
  const packStats: PackStats[] = [];
  for (const row of result) {
    const topRules = await db
      .select({ ruleId: dcgBlocks.ruleId })
      .from(dcgBlocks)
      .where(eq(dcgBlocks.pack, row.pack))
      .groupBy(dcgBlocks.ruleId)
      .orderBy(desc(count()))
      .limit(3);

    packStats.push({
      pack: row.pack,
      blockCount: row.blockCount,
      percentage: (row.blockCount / total) * 100,
      rules: row.rules,
      topRules: topRules.map(r => r.ruleId),
    });
  }

  return packStats;
}

async function getAgentStats(limit: number): Promise<AgentStats[]> {
  const totalBlocks = await db.select({ count: count() }).from(dcgBlocks);
  const total = totalBlocks[0]?.count || 1;

  const result = await db
    .select({
      agentId: dcgBlocks.agentId,
      blockCount: count(),
      lastBlock: sql<Date>`MAX(${dcgBlocks.createdAt})`,
    })
    .from(dcgBlocks)
    .where(sql`${dcgBlocks.agentId} IS NOT NULL`)
    .groupBy(dcgBlocks.agentId)
    .orderBy(desc(count()))
    .limit(limit);

  const agentStats: AgentStats[] = [];
  for (const row of result) {
    const topRules = await db
      .select({ ruleId: dcgBlocks.ruleId })
      .from(dcgBlocks)
      .where(eq(dcgBlocks.agentId, row.agentId!))
      .groupBy(dcgBlocks.ruleId)
      .orderBy(desc(count()))
      .limit(3);

    agentStats.push({
      agentId: row.agentId!,
      blockCount: row.blockCount,
      percentage: (row.blockCount / total) * 100,
      topRules: topRules.map(r => r.ruleId),
      lastBlock: row.lastBlock,
    });
  }

  return agentStats;
}

async function getHourlyTimeSeries(hours: number): Promise<TimeSeriesPoint[]> {
  const since = Date.now() - hours * 60 * 60 * 1000;

  const result = await db
    .select({
      hour: sql<string>`strftime('%Y-%m-%d %H:00:00', ${dcgBlocks.createdAt}, 'unixepoch')`,
      count: count(),
    })
    .from(dcgBlocks)
    .where(gte(dcgBlocks.createdAt, new Date(since)))
    .groupBy(sql`strftime('%Y-%m-%d %H:00:00', ${dcgBlocks.createdAt}, 'unixepoch')`)
    .orderBy(sql`strftime('%Y-%m-%d %H:00:00', ${dcgBlocks.createdAt}, 'unixepoch')`);

  return result.map(row => ({
    timestamp: new Date(row.hour),
    count: row.count,
  }));
}

async function getDailyTimeSeries(days: number): Promise<TimeSeriesPoint[]> {
  const since = Date.now() - days * 24 * 60 * 60 * 1000;

  const result = await db
    .select({
      day: sql<string>`strftime('%Y-%m-%d', ${dcgBlocks.createdAt}, 'unixepoch')`,
      count: count(),
    })
    .from(dcgBlocks)
    .where(gte(dcgBlocks.createdAt, new Date(since)))
    .groupBy(sql`strftime('%Y-%m-%d', ${dcgBlocks.createdAt}, 'unixepoch')`)
    .orderBy(sql`strftime('%Y-%m-%d', ${dcgBlocks.createdAt}, 'unixepoch')`);

  return result.map(row => ({
    timestamp: new Date(row.day),
    count: row.count,
  }));
}

async function getRecentBlocks(limit: number): Promise<DCGBlockEvent[]> {
  return await db
    .select()
    .from(dcgBlocks)
    .orderBy(desc(dcgBlocks.createdAt))
    .limit(limit);
}

// Lightweight stats for dashboard widgets
export async function getQuickStats(): Promise<{
  blocksToday: number;
  pendingExceptions: number;
  falsePositiveRate: number;
}> {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const [blocksToday, pending, fpRate] = await Promise.all([
    db.select({ count: count() }).from(dcgBlocks)
      .where(gte(dcgBlocks.createdAt, today)),
    db.select({ count: count() }).from(dcgPendingExceptions)
      .where(eq(dcgPendingExceptions.status, "pending")),
    db.select({
      total: count(),
      fp: sql<number>`SUM(CASE WHEN ${dcgBlocks.falsePositive} THEN 1 ELSE 0 END)`,
    }).from(dcgBlocks),
  ]);

  const total = fpRate[0]?.total || 1;
  const fpCount = fpRate[0]?.fp || 0;

  return {
    blocksToday: blocksToday[0]?.count || 0,
    pendingExceptions: pending[0]?.count || 0,
    falsePositiveRate: (fpCount / total) * 100,
  };
}
