### 2. REST API Routes

```typescript
// routes/dcg.ts - Update stats endpoints

// GET /dcg/stats - Full statistics
dcg.get("/stats", async (c) => {
  const stats = await getStats();
  return c.json(stats);
});

// GET /dcg/stats/quick - Lightweight stats for widgets
dcg.get("/stats/quick", async (c) => {
  const stats = await getQuickStats();
  return c.json(stats);
});

// GET /dcg/stats/timeseries - Time series data
dcg.get("/stats/timeseries", async (c) => {
  const period = c.req.query("period") || "hourly";
  const points = Number(c.req.query("points")) || 24;

  const data = period === "daily"
    ? await getDailyTimeSeries(points)
    : await getHourlyTimeSeries(points);

  return c.json({ period, data });
});

// GET /dcg/stats/by-pack - Stats grouped by pack
dcg.get("/stats/by-pack", async (c) => {
  const packStats = await getPackStats();
  return c.json({ packs: packStats });
});

// GET /dcg/stats/by-agent - Stats grouped by agent
dcg.get("/stats/by-agent", async (c) => {
  const limit = Number(c.req.query("limit")) || 10;
  const agentStats = await getAgentStats(limit);
  return c.json({ agents: agentStats });
});

// GET /dcg/stats/top-rules - Top triggered rules
dcg.get("/stats/top-rules", async (c) => {
  const limit = Number(c.req.query("limit")) || 10;
  const topRules = await getTopRules(limit);
  return c.json({ rules: topRules });
});
